"""matplotlib._api.deprecation — deprecation decorators."""

import warnings

def deprecated(since, *, message='', name='', alternative='',
               pending=False, obj_type='', addendum='', removal=''):
    def decorator(obj):
        return obj
    return decorator

def warn_deprecated(since, *, message='', name='', alternative='',
                    pending=False, obj_type='', addendum='', removal=''):
    warnings.warn(f'{name} is deprecated since {since}', DeprecationWarning, stacklevel=2)

class MatplotlibDeprecationWarning(DeprecationWarning):
    pass

mplDeprecation = MatplotlibDeprecationWarning

def rename_parameter(since, old, new, func=None):
    if func is None:
        return lambda f: f
    return func

def delete_parameter(since, name, func=None, **kwargs):
    if func is None:
        return lambda f: f
    return func

def make_keyword_only(since, name, func=None):
    if func is None:
        return lambda f: f
    return func
